import{_ as o,o as t,c as n,ae as s}from"./chunks/framework.BMBGeRFM.js";const u=JSON.parse('{"title":"Conventions and Idioms","description":"","frontmatter":{},"headers":[],"relativePath":"conventions/index.md","filePath":"conventions/index.md"}'),i={name:"conventions/index.md"};function a(r,e,d,c,m,l){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="conventions-and-idioms" tabindex="-1">Conventions and Idioms <a class="header-anchor" href="#conventions-and-idioms" aria-label="Permalink to &quot;Conventions and Idioms&quot;">​</a></h1><p>Writing text in Farben is easy, and most of the time it works with no problem, but it&#39;s best to remind yourself that it could be better.</p><p>Idioms are <em>good ways to use Farben</em>, whether it be deciding correct functions for correct use cases, or just ways to make working with Farben much nicer. As good programmers, it&#39;s best to follow these designed idioms.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Of course, Farben doesn&#39;t <em>care</em> about idioms. It just cares if your input is correct, even if it&#39;s wonky. Which is why idioms are recommended. Farben can read messy code, sure, but contributors may not. They&#39;re not a machine, after all.</p></div><p>Let&#39;s explore common dilemmas and idioms for Farben.</p>',5)])])}const _=o(i,[["render",a]]);export{u as __pageData,_ as default};
